diff --git a/src/MediatR/Wrappers/NotificationHandlerWrapper.cs b/src/MediatR/Wrappers/NotificationHandlerWrapper.cs
index 404fe3f..e69a3d3 100644
--- a/src/MediatR/Wrappers/NotificationHandlerWrapper.cs
+++ b/src/MediatR/Wrappers/NotificationHandlerWrapper.cs
@@ -21,11 +21,27 @@ public class NotificationHandlerWrapperImpl<TNotification> : NotificationHandler
         Func<IEnumerable<NotificationHandlerExecutor>, INotification, CancellationToken, Task> publish,
         CancellationToken cancellationToken)
     {
-        var handlers = serviceFactory
+        var concreteHandlers = serviceFactory
             .GetServices<INotificationHandler<TNotification>>()
-            .GroupBy(static x => x.GetType())
-            .Select(static g => g.First())
-            .Select(static x => new NotificationHandlerExecutor(x, (theNotification, theToken) => x.Handle((TNotification)theNotification, theToken)));
+            .Distinct(ReferenceEqualityComparer.Instance);
+
+        var interfaceHandlers = typeof(TNotification)
+            .GetInterfaces()
+            .Where(static i => i != typeof(INotification) && typeof(INotification).IsAssignableFrom(i))
+            .SelectMany(interfaceType =>
+            {
+                var handlerType = typeof(INotificationHandler<>).MakeGenericType(interfaceType);
+                var handleMethod = handlerType.GetMethod(nameof(INotificationHandler<TNotification>.Handle))!;
+                return serviceFactory
+                    .GetServices(handlerType)
+                    .Where(static h => h != null)
+                    .Select(h => new NotificationHandlerExecutor(h!,
+                        (theNotification, theToken) => (System.Threading.Tasks.Task)handleMethod.Invoke(h, new object[] { theNotification, theToken })!));
+            });
+
+        var handlers = concreteHandlers
+            .Select(static x => new NotificationHandlerExecutor(x, (theNotification, theToken) => x.Handle((TNotification)theNotification, theToken)))
+            .Concat(interfaceHandlers);

         return publish(handlers, notification, cancellationToken);
     }
